Below is a **complete, self‑contained example** that shows how to expose a C++ iterator‑style API from the (fictional) `libpcapng` library to Python with **pybind11**.  

* The C++ side implements a thin wrapper (`Reader`) that owns a `PcapNGFile` object, provides a Python‑friendly iterator (`ReaderIter`) and a convenience method `for_each(callback)` that calls a user‑supplied Python function for every frame.  
* The iterator releases the GIL while it is reading frames from the file and reacquires it only when the Python callback is invoked – this lets the C++ side run at full speed without blocking the interpreter.  
* The Python‑facing API is deliberately small and “Pythonic”: you can either iterate with a normal `for … in …` loop **or** call `Reader.for_each` with any callable (function, lambda, bound method, etc.).  

> **NOTE** – The code below assumes you already have a compiled `libpcapng` library that provides the classes `PcapNGFile`, `Frame` and the associated iterator.  The exact header names are placeholders (`<pcapng/pcapng.hpp>`) – replace them with the real ones from your library.

---

## 1. C++ binding source (`pcapng_bindings.cpp`)

```cpp
//===================================================================
//  pcapng_bindings.cpp
//  -------------------
//  Pybind11 bindings for libpcapng (C++ network‑capture parser).
//
//  Build (example with CMake):
//      mkdir build && cd build
//      cmake -DPYTHON_EXECUTABLE=$(which python3) ..
//      make
//
//  The resulting shared object can be imported as `import pcapng`.
//===================================================================

#include <pybind11/pybind11.h>
#include <pybind11/functional.h>   // for std::function <-> python callable
#include <pybind11/stl.h>          // optional: expose std::vector, std::string, etc.
#include <pybind11/chrono.h>       // expose std::chrono types (if needed)
#include <pybind11/iostream.h>     // optional: redirect C++ std::cout

namespace py = pybind11;

// -------------------------------------------------------------------
//  Fake include of the real libpcapng – replace with your actual header(s)
// -------------------------------------------------------------------
#include <pcapng/pcapng.hpp>   // <-- real header(s) from libpcapng

// -------------------------------------------------------------------
//  Helper: a thin C++ wrapper that owns the file object and provides
//  Python‑friendly iteration.
// -------------------------------------------------------------------
class Reader {
public:
    // Construct from a path – throws on error (converted to Python exception)
    explicit Reader(const std::string& path) : file_(std::make_shared<PcapNGFile>(path)) {}

    // ----------------------------------------------------------------
    //  Python iterator object – separate class so we can implement __iter__
    //  and __next__ directly.
    // ----------------------------------------------------------------
    class Iterator {
    public:
        explicit Iterator(std::shared_ptr<PcapNGFile> file)
            : file_(std::move(file)), it_(file_->begin()), end_(file_->end()) {}

        // Python's __iter__ – returns self
        Iterator& __iter__() { return *this; }

        // Python's __next__ – returns next Frame or raises StopIteration
        py::object __next__() {
            // Fast‑path: if we are already at end, raise StopIteration.
            if (it_ == end_) {
                throw py::stop_iteration();
            }

            // Grab the frame *before* releasing the GIL – the Frame object
            // lives on the C++ side, we will copy it into a new Python wrapper.
            const Frame& cframe = *it_;
            ++it_;   // advance iterator for the next call

            // Build a Python Frame object (see binding below) by copying.
            // The copy is cheap – usually just a few pointers / timestamps.
            return py::cast(Frame(cframe));
        }

    private:
        std::shared_ptr<PcapNGFile> file_;   // keep file alive for iterator lifetime
        PcapNGFile::iterator it_;
        PcapNGFile::iterator end_;
    };

    // ----------------------------------------------------------------
    //  Return a fresh iterator (Python will call __iter__ on it)
    // ----------------------------------------------------------------
    Iterator iter() const { return Iterator(file_); }

    // ----------------------------------------------------------------
    //  Convenience: call a Python callable for each frame.
    //  The GIL is released while we read frames, reacquired only for the
    //  callback – this is the most efficient pattern when the user only
    //  wants to *process* frames.
    // ----------------------------------------------------------------
    void for_each(py::function py_callback) const {
        // Release GIL while we walk the C++ iterator.
        py::gil_scoped_release release;
        for (auto it = file_->begin(); it != file_->end(); ++it) {
            // Re‑acquire GIL *just* before invoking the Python callable.
            py::gil_scoped_acquire acquire;
            py_callback(*it);          // *it is a const Frame& – pybind11 copies it.
        }
    }

    // ----------------------------------------------------------------
    //  Context‑manager support (optional but nice): `with Reader(...) as r: …`
    // ----------------------------------------------------------------
    Reader* __enter__() { return this; }
    void __exit__(py::object, py::object, py::object) {
        // The shared_ptr will clean up automatically when this object is
        // destroyed at the end of the with‑block.
    }

private:
    std::shared_ptr<PcapNGFile> file_;
};

// -------------------------------------------------------------------
//  Bindings
// -------------------------------------------------------------------
PYBIND11_MODULE(pcapng, m) {
    m.doc() = R"pbdoc(
        Python bindings for libpcapng – a parser for PCAP‑NG capture files.

        Example
        -------
        >>> from pcapng import Reader
        >>> def show(frame):
        ...     print(frame.timestamp, len(frame.data))
        ...
        >>> with Reader("sample.pcapng") as r:
        ...     r.for_each(show)          # callback style
        ...     for f in r:               # iterator style
        ...         show(f)
        ...
    )pbdoc";

    // ----------------------------------------------------------------
    //  Expose the Frame class – adjust members to match your real Frame.
    // ----------------------------------------------------------------
    py::class_<Frame>(m, "Frame", R"pbdoc(
        Represents a single captured frame (packet) from a PCAP‑NG file.

        Attributes
        ----------
        timestamp : datetime.datetime
            Capture time of the frame (UTC).
        data : bytes
            Raw packet bytes.
        orig_len : int
            Original length on the wire (may be larger than `len(data)`).
    )pbdoc")
        // Assuming Frame provides: std::chrono::system_clock::time_point timestamp()
        // and std::vector<uint8_t> data();  and uint32_t original_len()
        .def_property_readonly("timestamp",
            [](const Frame& f) {
                // Convert std::chrono::system_clock::time_point to Python datetime
                using namespace std::chrono;
                auto tp = f.timestamp();                     // C++ time_point
                auto secs = duration_cast<seconds>(tp.time_since_epoch()).count();
                auto nsecs = duration_cast<nanoseconds>(tp.time_since_epoch()).count() % 1000000000;
                py::module datetime = py::module::import("datetime");
                py::object datetime_class = datetime.attr("datetime");
                return datetime_class(secs / 86400 + 719163,   // days since 0001‑01‑01
                                      (secs % 86400) / 3600 + 1,
                                      (secs % 3600) / 60 + 1,
                                      secs % 60,
                                      nsecs / 1000);
            },
            "Capture timestamp as a Python ``datetime`` (UTC).")
        .def_property_readonly("data",
            [](const Frame& f) {
                // Convert raw vector<uint8_t> to Python bytes
                const auto& vec = f.data();
                return py::bytes(reinterpret_cast<const char*>(vec.data()), vec.size());
            },
            "Raw packet bytes.")
        .def_property_readonly("orig_len",
            &Frame::original_len,
            "Original length of the packet on the wire.");

    // ----------------------------------------------------------------
    //  Expose the Reader class.
    // ----------------------------------------------------------------
    py::class_<Reader>(m, "Reader", R"pbdoc(
        High‑level entry point for reading a PCAP‑NG file.

        Parameters
        ----------
        path : str
            Path to the capture file.

        The object is iterable – each iteration yields a :class:`Frame`.
        It also implements the context‑manager protocol so you can write:

        >>> with Reader('file.pcapng') as r:
        ...     for f in r: …
        )pbdoc")
        .def(py::init<const std::string&>(),
             py::arg("path"),
             "Open a PCAP‑NG file for reading.")
        // Python iterator protocol – ``__iter__`` returns an iterator object.
        .def("__iter__", &Reader::iter, py::keep_alive<0, 1>(),
             "Return an iterator over the frames in the capture.")
        // Convenience method that takes a Python callable.
        .def("for_each",
             &Reader::for_each,
             py::arg("callback"),
             "Call ``callback(frame)`` for each frame in the file.\n"
             "The GIL is released while reading, and reacquired only for the callback.")
        // Context‑manager helpers
        .def("__enter__", &Reader::__enter__, py::return_value_policy::reference_internal)
        .def("__exit__", &Reader::__exit__);

    // ----------------------------------------------------------------
    //  (Optional) expose the iterator class directly – useful for type
    //  checking or manual iteration.
    // ----------------------------------------------------------------
    py::class_<Reader::Iterator>(m, "ReaderIter")
        .def("__iter__", &Reader::Iterator::__iter__, py::return_value_policy::reference_internal)
        .def("__next__", &Reader::Iterator::__next__);
}
```

### What the binding does

| Python feature | C++ implementation |
|----------------|--------------------|
| **`Reader(path)`** – open a file | `Reader` ctor stores a `shared_ptr<PcapNGFile>`  |
| **Iteration** – `for f in r:` | `Reader.iter()` returns a custom `Iterator` that implements `__iter__`/`__next__`. The iterator copies each `Frame` into a new Python `Frame` object. |
| **Callback style** – `r.for_each(callback)` | `Reader.for_each` walks the native iterator, releasing the GIL while reading and reacquiring it only when invoking the Python callable. |
| **Context manager** – `with Reader(...) as r:` | `__enter__`/`__exit__` simply return the object; the `shared_ptr` ensures proper clean‑up. |
| **`Frame` attributes** – `timestamp`, `data`, `orig_len` | Property getters convert `std::chrono` → `datetime.datetime`, `std::vector<uint8_t>` → `bytes`, and expose the original length. |

