## 2. Minimal CMake file (optional – for building the module)

```cmake
# CMakeLists.txt
cmake_minimum_required(VERSION 3.14)
project(pcapng_bindings LANGUAGES CXX)

# Find Python interpreter & development headers
find_package(Python3 COMPONENTS Interpreter Development REQUIRED)

# Find pybind11 (you can also use FetchContent to pull it in)
find_package(pybind11 CONFIG REQUIRED)

# Find the real libpcapng (replace with your own find_package or
# add_library if you have a static lib)
find_library(PCAPNG_LIB pcapng REQUIRED)

add_library(pcapng MODULE pcapng_bindings.cpp)

target_include_directories(pcapng PRIVATE ${PCAPNG_INCLUDE_DIR}) # if needed
target_link_libraries(pcapng PRIVATE pybind11::module ${PCAPNG_LIB})

# Ensure the output file has the proper suffix for a Python extension
set_target_properties(pcapng PROPERTIES
    PREFIX "${PYTHON_MODULE_PREFIX}"
    SUFFIX "${PYTHON_MODULE_EXTENSION}"
)
```

Running:

```bash
mkdir -p build && cd build
cmake -DPython3_EXECUTABLE=$(which python3) ..
make
```

will produce `pcapng.cpython-311-x86_64-linux-gnu.so` (or similar) that can be imported directly:

```python
>>> import pcapng
>>> help(pcapng.Reader)
```

