## 3. Example Python usage

```python
# demo.py
import pcapng
from datetime import datetime

def print_frame(frame):
    """Simple callback – prints timestamp and packet length."""
    # `frame.timestamp` is a datetime.datetime (UTC)
    # `frame.data` is a bytes object
    print(f"{frame.timestamp.isoformat()}  len={len(frame.data)}  orig_len={frame.orig_len}")

def main():
    pcap_path = "samples/example.pcapng"

    # -----------------------------------------------------------------
    #   1) Callback style – most efficient when you only need to *process*
    # -----------------------------------------------------------------
    with pcapng.Reader(pcap_path) as rdr:
        print("=== Using for_each(callback) ===")
        rdr.for_each(print_frame)

    # -----------------------------------------------------------------
    #   2) Iterator style – Pythonic, works with any generator expression
    # -----------------------------------------------------------------
    print("\n=== Using Python iteration ===")
    with pcapng.Reader(pcap_path) as rdr:
        for frm in rdr:
            # You can do anything here – filter, map, accumulate, etc.
            if len(frm.data) > 1000:          # arbitrary filter example
                print_frame(frm)

    # -----------------------------------------------------------------
    #   3) Using the iterator class directly (rarely needed)
    # -----------------------------------------------------------------
    print("\n=== Direct iterator object ===")
    rdr = pcapng.Reader(pcap_path)
    it = rdr.iter()          # returns a ReaderIter instance
    try:
        while True:
            frm = next(it)
            print_frame(frm)
    except StopIteration:
        pass

if __name__ == "__main__":
    main()
```

